import{o as n,c as a,d as s}from"./app.dc6c1a1f.js";const e='{"title":"Docker Compose","description":"","frontmatter":{"title":"Docker Compose"},"headers":[{"level":2,"title":"安装","slug":"安装"},{"level":2,"title":"Usage","slug":"usage"},{"level":2,"title":"案例","slug":"案例"},{"level":3,"title":"Django","slug":"django"},{"level":3,"title":"Gin","slug":"gin"}],"relativePath":"docs/cloud-native/compose/README.md","lastUpdated":1648542898175}',o={},t=s('<h2 id="安装"><a class="header-anchor" href="#安装" aria-hidden="true">#</a> 安装</h2><div class="language-shell"><pre><code><span class="token assign-left variable">DOCKER_CONFIG</span><span class="token operator">=</span><span class="token variable">${DOCKER_CONFIG<span class="token operator">:-</span>$HOME<span class="token operator">/</span>.docker}</span>\n<span class="token function">mkdir</span> -p <span class="token variable">$DOCKER_CONFIG</span>/cli-plugins\n<span class="token function">curl</span> -SL https://github.com/docker/compose/releases/download/v2.2.3/docker-compose-linux-x86_64 -o <span class="token variable">$DOCKER_CONFIG</span>/cli-plugins/docker-compose\n<span class="token function">chmod</span> +x <span class="token variable">$DOCKER_CONFIG</span>/cli-plugins/docker-compose\n</code></pre></div><div class="language-shell"><pre><code>➜  ~ docker compose version\nDocker Compose version v2.2.3\n</code></pre></div><h2 id="usage"><a class="header-anchor" href="#usage" aria-hidden="true">#</a> Usage</h2><p><code>build</code> Build or rebuild services</p><p><code>down</code> Stop and remove containers, networks. -v, --volumes volumes <strong>推荐使用</strong></p><p><code>ls</code> List running compose projects</p><p><code>ps</code> List containers</p><p><code>pull</code> Pull service images</p><p><code>restart</code> Restart containers</p><p><code>rm</code> Removes stopped service containers</p><p><code>start</code> Start services</p><p><code>stop</code> Stop services</p><p><code>up</code> Create and start containers. -d, --detach, Detached mode: 容器在后台运行</p><h2 id="案例"><a class="header-anchor" href="#案例" aria-hidden="true">#</a> 案例</h2><h3 id="django"><a class="header-anchor" href="#django" aria-hidden="true">#</a> Django</h3><p>Django + Nginx</p><h4 id="目录结构"><a class="header-anchor" href="#目录结构" aria-hidden="true">#</a> 目录结构</h4><div class="language-shell"><pre><code>├── backend\n│   └── Dockerfile\n├── docker-compose.yml\n└── frontend\n    ├── Dockerfile\n    └── nginx\n        └── default.template\n</code></pre></div><div class="language-yaml"><pre><code><span class="token key atrule">version</span><span class="token punctuation">:</span> <span class="token string">&quot;3&quot;</span>\n<span class="token key atrule">services</span><span class="token punctuation">:</span>\n  <span class="token key atrule">backend</span><span class="token punctuation">:</span>\n    <span class="token key atrule">container_name</span><span class="token punctuation">:</span> lcm_backend\n    <span class="token key atrule">sysctls</span><span class="token punctuation">:</span>\n      <span class="token key atrule">net.core.somaxconn</span><span class="token punctuation">:</span> <span class="token number">65535</span>\n    <span class="token key atrule">build</span><span class="token punctuation">:</span> ./backend/\n    <span class="token key atrule">image</span><span class="token punctuation">:</span> backend<span class="token punctuation">:</span><span class="token number">1.4</span>\n<span class="token comment">#    volumes:</span>\n<span class="token comment">#      - ./backend/archerosLcm2:/code</span>\n    <span class="token key atrule">environment</span><span class="token punctuation">:</span>\n      <span class="token punctuation">-</span> CLOUD_NAME=pdd\n      <span class="token punctuation">-</span> HY_TOOLS_CONF=testing\n      <span class="token punctuation">-</span> SCAN_HOST_LIST=10.192.116.11 10.192.116.12 10.192.116.13\n      <span class="token punctuation">-</span> DEPLOY_CALLBACK_URL=192.168.1.10\n<span class="token comment">#    command: bash -c &quot;gunicorn archerosLcm2.asgi:application -k uvicorn.workers.UvicornWorker --capture-output -b 0.0.0.0:51381 &amp;&amp; celery multi start w1 -A archerosLcm2 -P solo --time-limit=300 --concurrency=1 -l info --logfile=/tmp/celery.log&quot;</span>\n    <span class="token key atrule">command</span><span class="token punctuation">:</span> bash <span class="token punctuation">-</span>c &quot;gunicorn <span class="token punctuation">-</span>c /usr/local/archeros<span class="token punctuation">-</span>lcm/conf/gunicorn.conf.py &amp; celery <span class="token punctuation">-</span>A archerosLcm2 worker <span class="token punctuation">-</span>P solo <span class="token punctuation">-</span><span class="token punctuation">-</span>time<span class="token punctuation">-</span>limit=300 <span class="token punctuation">-</span><span class="token punctuation">-</span>concurrency=1 <span class="token punctuation">-</span>l info <span class="token punctuation">-</span><span class="token punctuation">-</span>logfile=/tmp/celery.log&quot;\n<span class="token comment">#    ports:</span>\n<span class="token comment">#      - 51381:51381</span>\n    <span class="token key atrule">restart</span><span class="token punctuation">:</span> on<span class="token punctuation">-</span>failure\n  <span class="token key atrule">frontend</span><span class="token punctuation">:</span>\n    <span class="token key atrule">container_name</span><span class="token punctuation">:</span> lcm_frontend\n    <span class="token key atrule">build</span><span class="token punctuation">:</span> ./frontend/\n    <span class="token key atrule">image</span><span class="token punctuation">:</span> frontend<span class="token punctuation">:</span><span class="token number">1.4</span>\n    <span class="token key atrule">environment</span><span class="token punctuation">:</span>\n      <span class="token punctuation">-</span> BACKEND=backend\n    <span class="token key atrule">command</span><span class="token punctuation">:</span> bash <span class="token punctuation">-</span>c &quot;envsubst &#39;$$BACKEND&#39; &lt; /etc/nginx/conf.d/default.template <span class="token punctuation">&gt;</span> /etc/nginx/conf.d/default.conf <span class="token important">&amp;&amp;</span> exec nginx <span class="token punctuation">-</span>g &#39;daemon off;&#39;&quot;\n    <span class="token key atrule">ports</span><span class="token punctuation">:</span>\n      <span class="token punctuation">-</span> 51380<span class="token punctuation">:</span><span class="token number">51380</span>\n    <span class="token key atrule">restart</span><span class="token punctuation">:</span> always\n</code></pre></div><h4 id="运行"><a class="header-anchor" href="#运行" aria-hidden="true">#</a> 运行</h4><p>当前目录下，<code>docker-compose up -d</code></p><h3 id="gin"><a class="header-anchor" href="#gin" aria-hidden="true">#</a> Gin</h3><p>Gin + Nginx</p><h4 id="目录结构-1"><a class="header-anchor" href="#目录结构-1" aria-hidden="true">#</a> 目录结构</h4><div class="language-shell"><pre><code>├── docker-compose.yml\n├── mysql\n│   └── init\n│       └── sdn.sql\n├── redis\n│   └── redis.conf\n├── server\n│   ├── Dockerfile\n│   └── wait-for.sh\n└── web\n    ├── Dockerfile\n    └── nginx\n        └── default.conf\n</code></pre></div><h4 id="运行-1"><a class="header-anchor" href="#运行-1" aria-hidden="true">#</a> 运行</h4><p>当前目录下，<code>docker-compose up -d</code></p>',28);o.render=function(s,e,o,p,c,l){return n(),a("div",null,[t])};export default o;export{e as __pageData};
